        ),
        0.75,
      );
      expect(
        FractalEffectInputBounds.normalizeKaleidoscopeRotation(
          candidate: double.infinity,
          current: 0.75,
        ),
        0.75,
      );
    });
  });
}

import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:vector_math/vector_math.dart';

/// Pure bounds for gesture/view input accepted by FractalController.
///
/// Dart's [double.clamp] treats NaN as the upper bound. Gesture telemetry and
/// replayed state can occasionally contain NaN, and promoting that to max zoom
/// or max pan makes failures hard to replay. Preserve the last known-good value
/// for NaN while still clamping infinities to the explicit viewport limits.
/// Rotation has no explicit UI bounds, but shader uniforms still require finite
/// values; non-finite rotation components fall back to last known-good angles.
final class FractalViewInputBounds {
  static const double maxZoom = 1e12;
  static const double defaultMinZoom = 1e-9;
  static const double cantorSetMinZoom = 0.2;
  static const double minPan = -3.0;
  static const double maxPan = 3.0;

  const FractalViewInputBounds._();

  static double minZoomForModule(String moduleId) {
    switch (moduleId) {
      case 'cantor_set':
        // Prevent ultra-zoomed-out aliasing that appears as black vertical bands.
        return cantorSetMinZoom;
      default:
        return defaultMinZoom;
    }
  }

  static double normalizeZoom({
    required double candidate,
    required double currentZoom,
    required String moduleId,
  }) {
    final minZoom = minZoomForModule(moduleId);
    final fallback = currentZoom.isNaN ? minZoom : currentZoom;
    if (candidate.isNaN) return fallback.clamp(minZoom, maxZoom).toDouble();
    return candidate.clamp(minZoom, maxZoom).toDouble();
  }

  static double normalizePanComponent({
    required double candidate,
    required double current,
  }) {
    final fallback = current.isNaN ? 0.0 : current;
    if (candidate.isNaN) return fallback.clamp(minPan, maxPan).toDouble();
    return candidate.clamp(minPan, maxPan).toDouble();
  }

  static double normalizeRotationComponent({
    required double candidate,
    required double current,
  }) {
    if (candidate.isFinite) return candidate;
    return current.isFinite ? current : 0.0;
  }

  static Vector3 normalizeRotation({
    required Vector3 candidate,
    required Vector3 current,
  }) {
    return Vector3(
      normalizeRotationComponent(candidate: candidate.x, current: current.x),
      normalizeRotationComponent(candidate: candidate.y, current: current.y),
      normalizeRotationComponent(candidate: candidate.z, current: current.z),
    );
  }

  /// Sanitizes externally supplied view snapshots before they become controller
  /// state. Finite values preserve existing behavior; NaN values fall back to
  /// the last known-good view while infinities clamp to explicit bounds or, for
  /// unbounded rotation, fall back to the last known-good finite angle.
  static FractalViewState normalizeView({
    required FractalViewState candidate,
    required FractalViewState current,
    required String moduleId,
  }) {
    return candidate.copyWith(
      pan: Vector2(
        normalizePanComponent(
            candidate: candidate.pan.x, current: current.pan.x),
        normalizePanComponent(
            candidate: candidate.pan.y, current: current.pan.y),
      ),
      zoom: normalizeZoom(
        candidate: candidate.zoom,
        currentZoom: current.zoom,
        moduleId: moduleId,
      ),
      rotation: normalizeRotation(
        candidate: candidate.rotation,
        current: current.rotation,
      ),
    );
  }
}

import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_view_input_bounds.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart';

void main() {
  group('FractalViewInputBounds', () {
    test('preserves current zoom when candidate is NaN', () {
      expect(
        FractalViewInputBounds.normalizeZoom(
          candidate: double.nan,
          currentZoom: 42.0,
          moduleId: 'mandelbrot',
        ),
        42.0,
      );
    });

    test('falls back to module minimum when current and candidate zoom are NaN',
        () {
      expect(
        FractalViewInputBounds.normalizeZoom(
          candidate: double.nan,
          currentZoom: double.nan,
          moduleId: 'cantor_set',
        ),
        FractalViewInputBounds.cantorSetMinZoom,
      );
    });

    test('preserves current pan component when candidate is NaN', () {
      expect(
        FractalViewInputBounds.normalizePanComponent(
          candidate: double.nan,
          current: -1.25,
        ),
        -1.25,
      );
    });

    test('still clamps finite and infinite candidates to explicit bounds', () {
      expect(
        FractalViewInputBounds.normalizeZoom(
          candidate: double.infinity,
          currentZoom: 1.0,
          moduleId: 'mandelbrot',
        ),
        FractalViewInputBounds.maxZoom,
      );
      expect(
        FractalViewInputBounds.normalizePanComponent(
          candidate: -10.0,
          current: 0.0,
        ),
        FractalViewInputBounds.minPan,
      );
    });

    test('preserves current rotation component when candidate is non-finite',
        () {
      expect(
        FractalViewInputBounds.normalizeRotationComponent(
          candidate: double.nan,
          current: 0.75,
        ),
        0.75,
      );
      expect(
        FractalViewInputBounds.normalizeRotationComponent(
          candidate: double.infinity,
          current: double.nan,
        ),
        0.0,
      );
    });

    test('normalizes externally loaded view snapshots as one invariant', () {
      final normalized = FractalViewInputBounds.normalizeView(
        candidate: FractalViewState(
          pan: Vector2(double.nan, double.infinity),
          zoom: double.nan,
          rotation: Vector3(double.nan, double.infinity, 3),
        ),
        current: FractalViewState(
          pan: Vector2(0.5, -0.5),
          zoom: 42.0,
          rotation: Vector3(0.25, double.nan, -1),
        ),
        moduleId: 'mandelbrot',
      );

      expect(normalized.zoom, 42.0);
      expect(normalized.pan.x, 0.5);
      expect(normalized.pan.y, FractalViewInputBounds.maxPan);
      expect(normalized.rotation, Vector3(0.25, 0.0, 3));
    });

    test('normalizes mixed finite and non-finite rotation updates', () {
      final normalized = FractalViewInputBounds.normalizeRotation(
        candidate: Vector3(double.nan, double.infinity, 2.0),
        current: Vector3(0.25, -0.5, 1.0),
      );

      expect(normalized, Vector3(0.25, -0.5, 2.0));
    });
  });
}

import 'dart:io';

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/services/renderer_settings_service.dart';

const bool kForceCpuFallback =
    bool.fromEnvironment('FORCE_CPU_FALLBACK', defaultValue: false);
// Android emulator GPU is allowed in auto mode. Runtime health probes in
// FractalViewerScreen enforce fast fallback to CPU on invalid output.

enum RendererBackend { gpu, cpu }

enum FallbackReasonCode {
  none,
  forcedByFlag,
  androidEmulator,
  gpuHealthCheckFailed,
  deepZoomPrecision,
  manualToggle,
  moduleUnsupported,
}

class BackendDecision {
  final RendererBackend backend;
  final FallbackReasonCode reasonCode;
  final String detail;

  const BackendDecision({
    required this.backend,
    required this.reasonCode,
    required this.detail,
  });

  bool get isFallback => backend == RendererBackend.cpu;

  String get reasonToken {
    switch (reasonCode) {
      case FallbackReasonCode.none:
        return 'none';
      case FallbackReasonCode.forcedByFlag:
        return 'forced_by_flag';
      case FallbackReasonCode.androidEmulator:
        return 'android_emulator';
      case FallbackReasonCode.gpuHealthCheckFailed:
        return 'gpu_health_check_failed';
      case FallbackReasonCode.deepZoomPrecision:
        return 'deep_zoom_precision';
      case FallbackReasonCode.manualToggle:
        return 'manual_toggle';
      case FallbackReasonCode.moduleUnsupported:
        return 'module_unsupported';
    }
  }

  String toLogLine({required String moduleId}) {
    return '[renderer] backend_decision backend=${backend.name} reason=$reasonToken module=$moduleId detail=$detail';
  }

  String toUserStatusText() {
    if (!isFallback) return 'Renderer: GPU';
    switch (reasonCode) {
      case FallbackReasonCode.androidEmulator:
        return 'Using stable renderer for this Android emulator';
      case FallbackReasonCode.gpuHealthCheckFailed:
        return 'GPU output unavailable, using stable renderer';
      case FallbackReasonCode.deepZoomPrecision:
        return 'Deep zoom precision mode enabled';
      case FallbackReasonCode.manualToggle:
        return 'Renderer preference applied';
      case FallbackReasonCode.moduleUnsupported:
        return 'Stable renderer enabled for this fractal mode';
      case FallbackReasonCode.forcedByFlag:
        return 'Stable renderer forced by launch flag';
      case FallbackReasonCode.none:
        return 'Renderer: CPU';
    }
  }
}

class BackendPolicyInput {
  final bool isAndroid;
  final bool isWeb;
  final bool isEmulator;
  final RendererBackendMode userMode;
  final bool gpuHealthFailed;
  final bool deepZoomNeedsCpu;
  final FractalDimension dimension;

  const BackendPolicyInput({
    required this.isAndroid,
    required this.isWeb,
    required this.isEmulator,
    required this.userMode,
    required this.gpuHealthFailed,
    required this.deepZoomNeedsCpu,
    required this.dimension,
  });
}

/// Replayable explanation for the backend rule selected by the policy.
///
/// Platform probes are currently advisory in auto mode: Android emulator status
/// is logged and passed through, but runtime health checks decide fallback.
/// Keeping the selected rule visible makes that precedence testable instead of
/// hiding it in early returns.
class BackendPolicyResolution {
  final BackendDecision decision;
  final String selectedRule;
  final bool platformSignalsUsed;

  const BackendPolicyResolution({
    required this.decision,
    required this.selectedRule,
    required this.platformSignalsUsed,
  });
}

class RendererBackendPolicy {
  const RendererBackendPolicy();

  BackendDecision decide(BackendPolicyInput input) => explain(input).decision;

  BackendPolicyResolution explain(BackendPolicyInput input) {
    if (kForceCpuFallback) {
      return const BackendPolicyResolution(
        selectedRule: 'force_cpu_flag',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.forcedByFlag,
          detail: 'FORCE_CPU_FALLBACK=true',
        ),
      );
    }

    if (input.dimension != FractalDimension.twoD) {
      // 3D modules (e.g. Mandelbulb/Mandelbox) currently rely on GPU shader
      // rendering. Forcing CPU here only produces a disabled placeholder pane.
      // Keep these modules on GPU by default.
      if (input.userMode == RendererBackendMode.cpuOnly) {
        return const BackendPolicyResolution(
          selectedRule: 'gpu_required_module_cpu_only_ignored',
          platformSignalsUsed: false,
          decision: BackendDecision(
            backend: RendererBackend.gpu,
            reasonCode: FallbackReasonCode.moduleUnsupported,
            detail: 'cpu_only_ignored_for_3d_gpu_required',
          ),
        );
      }
      return const BackendPolicyResolution(
        selectedRule: 'gpu_required_module',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.gpu,
          reasonCode: FallbackReasonCode.none,
          detail: '3d_gpu_path',
        ),
      );
    }

    if (input.userMode == RendererBackendMode.cpuOnly) {
      return const BackendPolicyResolution(
        selectedRule: 'manual_cpu_only',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.manualToggle,
          detail: 'cpu_only',
        ),
      );
    }

    if (input.userMode == RendererBackendMode.gpuOnly) {
      return const BackendPolicyResolution(
        selectedRule: 'manual_gpu_only',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.gpu,
          reasonCode: FallbackReasonCode.manualToggle,
          detail: 'gpu_only',
        ),
      );
    }

    // Emulator targets are handled like physical devices in auto mode.
    // Runtime GPU health checks own fallback decisions.

    if (input.gpuHealthFailed) {
      return const BackendPolicyResolution(
        selectedRule: 'gpu_health_failed',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.gpuHealthCheckFailed,
          detail: 'frame_probe_detected_invalid_gpu_output',
        ),
      );
    }

    if (input.deepZoomNeedsCpu) {
      return const BackendPolicyResolution(
        selectedRule: 'deep_zoom_precision',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.deepZoomPrecision,
          detail: 'deep_zoom_precision_policy',
        ),
      );
    }

    return const BackendPolicyResolution(
      selectedRule: 'healthy_gpu_target',
      platformSignalsUsed: false,
      decision: BackendDecision(
        backend: RendererBackend.gpu,
        reasonCode: FallbackReasonCode.none,
        detail: 'healthy_gpu_target',
      ),
    );
  }
}

/// Replayable Android emulator signal snapshot.
///
/// Device probing is intentionally best-effort and IO-heavy; keeping the
/// signal classifier pure makes marker drift testable without touching
/// `/proc`, `getprop`, or `/system` in unit tests.
class AndroidEmulatorSignals {
  final String cpuInfo;
  final String hardware;
  final String buildCharacteristics;
  final String productModel;
  final String buildProp;

  const AndroidEmulatorSignals({
    this.cpuInfo = '',
    this.hardware = '',
    this.buildCharacteristics = '',
    this.productModel = '',
    this.buildProp = '',
  });

  bool get isEmulator =>
      AndroidEmulatorMarkerCatalog.hasCpuInfoMarker(cpuInfo) ||
      AndroidEmulatorMarkerCatalog.hasHardwareMarker(hardware) ||
      AndroidEmulatorMarkerCatalog.hasBuildCharacteristicsMarker(
        buildCharacteristics,
      ) ||
      AndroidEmulatorMarkerCatalog.hasProductModelMarker(productModel) ||
      AndroidEmulatorMarkerCatalog.hasBuildPropMarker(buildProp);
}

/// Named emulator marker contract used by Android emulator signal detection.
///
/// The markers are intentionally conservative: substring checks are used only
/// for fields that can contain labels or full property files, while the direct
/// `ro.hardware` value must match a known virtual hardware token exactly.
class AndroidEmulatorMarkerCatalog {
  static const List<String> cpuInfoSubstrings = [
    'ranchu',
    'goldfish',
    'qemu',
    'android virtual processor',
  ];
  static const List<String> exactHardwareValues = ['ranchu', 'goldfish'];
  static const List<String> buildCharacteristicsSubstrings = ['emulator'];
  static const List<String> productModelSubstrings = [
    'sdk_gphone',
    'android sdk built for',
  ];
  static const List<String> buildPropSubstrings = [
    'ro.hardware=goldfish',
    'ro.hardware=ranchu',
    'sdk_gphone',
    'generic_x86',
  ];

  const AndroidEmulatorMarkerCatalog._();

  static bool hasCpuInfoMarker(String value) {
    return _containsAny(value, cpuInfoSubstrings);
  }

  static bool hasHardwareMarker(String value) {
    return exactHardwareValues.contains(value.trim().toLowerCase());
  }

  static bool hasBuildCharacteristicsMarker(String value) {
    return _containsAny(value, buildCharacteristicsSubstrings);
  }

  static bool hasProductModelMarker(String value) {
    return _containsAny(value, productModelSubstrings);
  }

  static bool hasBuildPropMarker(String value) {
    return _containsAny(value, buildPropSubstrings);
  }

  static bool _containsAny(String value, List<String> markers) {
    final normalized = value.toLowerCase();
    return markers.any(normalized.contains);
  }
}

Future<bool> detectAndroidEmulator() async {
  if (kIsWeb || !Platform.isAndroid) return false;

  var signals = const AndroidEmulatorSignals();

  // 1. /proc/cpuinfo — check for emulator markers
  try {
    signals = AndroidEmulatorSignals(
      cpuInfo: await File('/proc/cpuinfo').readAsString(),
    );
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  // 2. getprop — most reliable on modern emulators
  try {
    final result = await Process.run('getprop', ['ro.hardware']);
    signals = AndroidEmulatorSignals(hardware: result.stdout as String);
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  try {
    final result = await Process.run('getprop', ['ro.build.characteristics']);
    signals = AndroidEmulatorSignals(
      buildCharacteristics: result.stdout as String,
    );
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  try {
    final result = await Process.run('getprop', ['ro.product.model']);
    signals = AndroidEmulatorSignals(productModel: result.stdout as String);
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  // 3. /system/build.prop — fallback file check
  try {
    signals = AndroidEmulatorSignals(
      buildProp: await File('/system/build.prop').readAsString(),
    );
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  return false;
}

import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/services/renderer_settings_service.dart';
import 'package:flutter_fractals/features/renderer/backend_policy.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  const policy = RendererBackendPolicy();

  // Helper to build a standard 2D auto input with overrides.
  BackendPolicyInput buildInput({
    bool isAndroid = false,
    bool isWeb = false,
    bool isEmulator = false,
    RendererBackendMode userMode = RendererBackendMode.auto,
    bool gpuHealthFailed = false,
    bool deepZoomNeedsCpu = false,
    FractalDimension dimension = FractalDimension.twoD,
  }) {
    return BackendPolicyInput(
      isAndroid: isAndroid,
      isWeb: isWeb,
      isEmulator: isEmulator,
      userMode: userMode,
      gpuHealthFailed: gpuHealthFailed,
      deepZoomNeedsCpu: deepZoomNeedsCpu,
      dimension: dimension,
    );
  }

  group('cpuOnly user mode', () {
    test('cpuOnly always returns cpu backend for 2D', () {
      final decision =
          policy.decide(buildInput(userMode: RendererBackendMode.cpuOnly));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });

    test('cpuOnly on non-emulator non-android still returns cpu', () {
      final decision = policy.decide(buildInput(
        isAndroid: false,
        isEmulator: false,
        userMode: RendererBackendMode.cpuOnly,
      ));
      expect(decision.backend, RendererBackend.cpu);
    });

    test('cpuOnly with gpuHealthFailed still returns cpu via manualToggle', () {
      // cpuOnly is evaluated before health-check; reason should be manualToggle
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.cpuOnly,
        gpuHealthFailed: true,
      ));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });

    test('cpuOnly is ignored for 3D module — GPU required', () {
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.cpuOnly,
        dimension: FractalDimension.threeD,
      ));
      // 3D always uses GPU; cpuOnly is overridden
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.moduleUnsupported);
    });
  });

  group('gpuOnly user mode', () {
    test('gpuOnly always returns gpu backend for 2D', () {
      final decision =
          policy.decide(buildInput(userMode: RendererBackendMode.gpuOnly));
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });

    test('gpuOnly bypasses deep-zoom CPU fallback', () {
      // gpuOnly is evaluated before deepZoomNeedsCpu check
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.gpuOnly,
        deepZoomNeedsCpu: true,
      ));
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });

    test('gpuOnly bypasses GPU health check', () {
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.gpuOnly,
        gpuHealthFailed: true,
      ));
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });
  });

  group('deep zoom CPU fallback', () {
    test('deepZoomNeedsCpu triggers cpu backend in auto mode', () {
      final decision = policy.decide(buildInput(deepZoomNeedsCpu: true));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.deepZoomPrecision);
    });

    test('deepZoomNeedsCpu reasonToken is deep_zoom_precision', () {
      final decision = policy.decide(buildInput(deepZoomNeedsCpu: true));
      expect(decision.reasonToken, 'deep_zoom_precision');
    });

    test('deepZoomNeedsCpu is evaluated after gpuHealthFailed', () {
      // gpuHealthFailed is checked first in the policy
      final decision = policy.decide(buildInput(
        gpuHealthFailed: true,
        deepZoomNeedsCpu: true,
      ));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.gpuHealthCheckFailed);
    });
  });

  group('GPU health failure', () {
    test('GPU health failure in auto mode returns cpu', () {
      final decision = policy.decide(buildInput(gpuHealthFailed: true));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.gpuHealthCheckFailed);
    });

    test('combined emulator + GPU health fail returns cpu', () {
      final decision = policy.decide(buildInput(
        isAndroid: true,
        isEmulator: true,
        gpuHealthFailed: true,
      ));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.gpuHealthCheckFailed);
    });

    test('isFallback is true when backend is cpu', () {
      final decision = policy.decide(buildInput(gpuHealthFailed: true));
      expect(decision.isFallback, isTrue);
    });
  });

  group('policy explanation', () {
    test('exposes selected rule while preserving decide compatibility', () {
      final resolution = policy.explain(buildInput(gpuHealthFailed: true));

      expect(resolution.selectedRule, 'gpu_health_failed');
      expect(resolution.platformSignalsUsed, isFalse);
      expect(resolution.decision.backend, RendererBackend.cpu);
      expect(policy.decide(buildInput(gpuHealthFailed: true)).reasonCode,
          resolution.decision.reasonCode);
    });

    test('documents platform signals as advisory in auto mode', () {
      final emulatorResolution = policy.explain(buildInput(
        isAndroid: true,
        isEmulator: true,
      ));
      final webResolution = policy.explain(buildInput(isWeb: true));

      expect(emulatorResolution.selectedRule, 'healthy_gpu_target');
      expect(emulatorResolution.platformSignalsUsed, isFalse);
      expect(webResolution.selectedRule, 'healthy_gpu_target');
      expect(webResolution.platformSignalsUsed, isFalse);
    });
  });

  group('healthy GPU with auto mode', () {
    test('healthy GPU with auto mode returns gpu', () {
      final decision = policy.decide(buildInput());
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.none);
    });

    test('isFallback is false for gpu decision', () {
      final decision = policy.decide(buildInput());
      expect(decision.isFallback, isFalse);
    });

    test('reasonToken is none for healthy GPU', () {
      final decision = policy.decide(buildInput());
      expect(decision.reasonToken, 'none');
    });

    test('toUserStatusText returns GPU label on healthy path', () {
      final decision = policy.decide(buildInput());
      expect(decision.toUserStatusText(), 'Renderer: GPU');
    });
  });

  group('3D module (unsupported GPU override)', () {
    test('3D module with auto mode uses GPU', () {
      final decision =
          policy.decide(buildInput(dimension: FractalDimension.threeD));
      expect(decision.backend, RendererBackend.gpu);
    });

    test('cpuOnly is ignored for 3D — moduleUnsupported reason', () {
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.cpuOnly,
        dimension: FractalDimension.threeD,
      ));
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.moduleUnsupported);
      expect(decision.reasonToken, 'module_unsupported');
    });

    test('3D module toUserStatusText returns GPU label (backend is gpu)', () {
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.cpuOnly,
        dimension: FractalDimension.threeD,
      ));
      // backend == gpu so isFallback is false; toUserStatusText returns 'Renderer: GPU'
      // regardless of reasonCode because the !isFallback check fires first.
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.isFallback, isFalse);
      expect(decision.toUserStatusText(), 'Renderer: GPU');
    });
  });

  group('AndroidEmulatorSignals', () {
    test('classifies each emulator marker without IO', () {
      const samples = [
        AndroidEmulatorSignals(cpuInfo: 'Hardware\t: ranchu'),
        AndroidEmulatorSignals(
            cpuInfo: 'Processor\t: Android Virtual Processor'),
        AndroidEmulatorSignals(cpuInfo: 'vendor_id\t: QEMU'),
        AndroidEmulatorSignals(hardware: ' goldfish\n'),
        AndroidEmulatorSignals(buildCharacteristics: 'nosdcard,emulator'),
        AndroidEmulatorSignals(productModel: 'sdk_gphone64_x86_64'),
        AndroidEmulatorSignals(productModel: 'Android SDK built for x86'),
        AndroidEmulatorSignals(buildProp: 'ro.hardware=ranchu\n'),
        AndroidEmulatorSignals(buildProp: 'ro.product.cpu.abi=generic_x86'),
      ];

      for (final sample in samples) {
        expect(sample.isEmulator, isTrue);
      }
    });

    test('does not classify physical-device-looking signals as emulator', () {
      const signals = AndroidEmulatorSignals(
        cpuInfo: 'Hardware\t: Qualcomm Technologies',
        hardware: 'qcom',
        buildCharacteristics: 'default',
        productModel: 'Pixel 8',
        buildProp: 'ro.hardware=qcom\nro.product.model=Pixel 8\n',
      );

      expect(signals.isEmulator, isFalse);
    });
  });

  group('BackendDecision helpers', () {
    test('toLogLine contains backend, reason, module, and detail', () {
      const decision = BackendDecision(
        backend: RendererBackend.cpu,
        reasonCode: FallbackReasonCode.deepZoomPrecision,
        detail: 'deep_zoom_precision_policy',
      );
      final line = decision.toLogLine(moduleId: 'mandelbrot');
      expect(line, contains('backend=cpu'));
      expect(line, contains('reason=deep_zoom_precision'));
      expect(line, contains('module=mandelbrot'));
      expect(line, contains('detail=deep_zoom_precision_policy'));
    });

    test('toUserStatusText for deep zoom precision', () {
      const decision = BackendDecision(
        backend: RendererBackend.cpu,
        reasonCode: FallbackReasonCode.deepZoomPrecision,
        detail: '',
      );
      expect(decision.toUserStatusText(), 'Deep zoom precision mode enabled');
    });

    test('toUserStatusText for manual toggle cpu', () {
      const decision = BackendDecision(
        backend: RendererBackend.cpu,
        reasonCode: FallbackReasonCode.manualToggle,
        detail: 'cpu_only',
      );
      expect(decision.toUserStatusText(), 'Renderer preference applied');
    });

    test('toUserStatusText for forced by flag', () {
      const decision = BackendDecision(
        backend: RendererBackend.cpu,
        reasonCode: FallbackReasonCode.forcedByFlag,
        detail: '',
      );
      expect(
          decision.toUserStatusText(), 'Stable renderer forced by launch flag');
    });
  });
}

import 'dart:math' as math;

import 'package:flutter/foundation.dart';

const double _mandelbrotDf2LowerThreshold = 5e6;
const double _mandelbrotDf2UpperThreshold = 1e12;
const double _escapeTimeCpuFallbackThreshold = 1e9;
const double _defaultCpuFallbackThreshold = 1e7;

/// Describes the precision boundaries for one fractal module.
@immutable
class DeepZoomThresholds {
  final double cpuFallbackZoom;
  final double? doubleFloatLowerZoom;
  final double? doubleFloatUpperZoom;

  const DeepZoomThresholds({
    required this.cpuFallbackZoom,
    this.doubleFloatLowerZoom,
    this.doubleFloatUpperZoom,
  })  : assert(
          (doubleFloatLowerZoom == null) == (doubleFloatUpperZoom == null),
          'double-float ranges must provide both lower and upper bounds',
        ),
        assert(
          (doubleFloatLowerZoom ?? double.negativeInfinity) <
              (doubleFloatUpperZoom ?? double.infinity),
          'double-float lower bound must be below upper bound',
        ),
        assert(
          (doubleFloatUpperZoom ?? double.negativeInfinity) <= cpuFallbackZoom,
          'double-float range must end no later than CPU fallback',
        );

  bool get supportsDoubleFloat => doubleFloatLowerZoom != null;

  bool shouldUseCpuFallback(double zoom) => zoom >= cpuFallbackZoom;

  bool shouldUseDoubleFloat(double zoom) {
    final lower = doubleFloatLowerZoom;
    final upper = doubleFloatUpperZoom;
    if (lower == null || upper == null) return false;
    return zoom >= lower && zoom < upper;
  }
}

/// Replayable precision routing decision for a module/zoom sample.
///
/// Renderer code needs CPU fallback and double-float eligibility to agree on
/// the same threshold snapshot. Keeping both booleans with their source
/// thresholds exposes that data-flow instead of recomputing partial decisions
/// at separate call sites.
@immutable
class DeepZoomPrecisionDecision {
  final String moduleId;
  final double zoom;
  final DeepZoomThresholds thresholds;

  const DeepZoomPrecisionDecision({
    required this.moduleId,
    required this.zoom,
    required this.thresholds,
  });

  bool get shouldUseCpuFallback => thresholds.shouldUseCpuFallback(zoom);
  bool get shouldUseDoubleFloat => thresholds.shouldUseDoubleFloat(zoom);
  double get cpuFallbackZoom => thresholds.cpuFallbackZoom;
}

/// Decides when GPU precision is likely insufficient at deep zoom.
///
/// ## Float32 precision analysis
///
/// GPU fragment shaders use float32 arithmetic (~7 significant digits,
/// mantissa ≈ 2^-24 ≈ 6e-8).
///
/// The coordinate span per pixel is: span_per_px = fractal_range / (zoom * resolution)
///   For a 1080p display and a fractal range of ~3 units:
///     span_per_px = 3 / (zoom * 1920) ≈ 1.6e-3 / zoom
///
/// Float32 artifacts appear when the per-pixel span drops below the
/// representable precision at the current center offset. In the worst case
/// (center near origin, no cancellation) this is roughly:
///     artifact threshold zoom ≈ 1.6e-3 / 6e-8 ≈ 2.7e4  ... but only at
///     an offset of ~1.0 unit from origin. Deep in the Mandelbrot boundary
///     where |c| ≈ 2, precision is consumed faster (≈ 1e4–1e5).
///     With the standard center at (0,0) or a well-normalized fractal,
///     artifacts are not visible until zoom ≈ 1e6–1e8.
///
/// Our shaders perform double-width emulation via paired float32 values
/// (see shader uniform layout) for a subset of fractals, extending usable
/// GPU range to ~1e12 before requiring CPU.
///
/// ## Conservative threshold policy
///
/// These thresholds are intentionally HIGH so GPU is used as long as
/// possible. The CPU fallback is a correctness escape hatch, not a
/// performance choice — it is significantly slower and disables GPU effects.
///
/// Raise these thresholds if you observe visible precision artifacts before
/// the switch; lower them only if tested on a low-DPI device where artifacts
/// appear earlier.
@immutable
class DeepZoomPrecisionPolicy {
  /// Maximum iterations we send to GPU shaders for real-time rendering.
  ///
  /// Most escape-time shaders clamp around this value already; keeping the
  /// cap centralized avoids overdriving slower devices at extreme zoom.
  static const int gpuMaxIterations = 2000;

  /// Per-module GPU→CPU fallback thresholds.
  ///
  /// For mandelbrot, the CPU fallback threshold is pushed to the df2 upper
  /// bound because the double-float shader [mandelbrot_df2.frag] covers the
  /// intermediate zoom range before CPU fallback.
  ///
  /// Other escape-time fractals still use float32 GPU up to their threshold,
  /// then fall back to CPU (no df2 variant available yet).
  static const Map<String, DeepZoomThresholds> _moduleThresholds = {
    // Mandelbrot: df2 shader covers zoom [5e6, 1e12), so CPU fallback only
    // kicks in at 1e12 (the df2 upper bound).
    'mandelbrot': DeepZoomThresholds(
      cpuFallbackZoom: _mandelbrotDf2UpperThreshold,
      doubleFloatLowerZoom: _mandelbrotDf2LowerThreshold,
      doubleFloatUpperZoom: _mandelbrotDf2UpperThreshold,
    ),
    // Julia & related escape-time fractals: GPU precision degrades sooner,
    // so switch to CPU around ~1e9.
    'julia': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'celtic': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'buffalo': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'burning_ship': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'tricorn': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot3': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot4': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot5': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'phoenix': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
  };

  /// Default threshold for any fractal type not listed above.
  /// Simple orbit fractals and non-escape-time types lose precision more
  /// slowly; 1e7 is a conservative upper bound for float32 at 1080p.
  static const DeepZoomThresholds _defaultThresholds = DeepZoomThresholds(
    cpuFallbackZoom: _defaultCpuFallbackThreshold,
  );

  /// Number of consecutive evaluations above the zoom threshold required
  /// before committing to CPU fallback. Prevents rapid GPU↔CPU flicker
  /// when zooming near the boundary.
  static const int _hysteresisFrames = 2;

  const DeepZoomPrecisionPolicy();

  /// Returns true when GPU precision is insufficient at the given zoom.
  ///
  /// Pure, stateless evaluation — callers that want hysteresis should
  /// use [DeepZoomHysteresis] to track frame counts.
  bool shouldUseCpuFallback({
    required String moduleId,
    required double zoom,
  }) {
    return decisionFor(moduleId: moduleId, zoom: zoom).shouldUseCpuFallback;
  }

  DeepZoomThresholds thresholdsFor(String moduleId) =>
      _moduleThresholds[moduleId] ?? _defaultThresholds;

  DeepZoomPrecisionDecision decisionFor({
    required String moduleId,
    required double zoom,
  }) {
    return DeepZoomPrecisionDecision(
      moduleId: moduleId,
      zoom: zoom,
      thresholds: thresholdsFor(moduleId),
    );
  }

  double thresholdFor(String moduleId) =>
      thresholdsFor(moduleId).cpuFallbackZoom;

  /// Returns true when the double-float shader should be used for [moduleId].
  ///
  /// Currently only mandelbrot has a df2 variant. The range is exclusive of
  /// the CPU fallback threshold.
  bool shouldUseDoubleFloat({
    required String moduleId,
    required double zoom,
  }) {
    return decisionFor(moduleId: moduleId, zoom: zoom).shouldUseDoubleFloat;
  }

  int get hysteresisFrames => _hysteresisFrames;

  /// Auto-scales iteration count with zoom depth for GPU rendering.
  ///
  /// Keeps shallow zoom responsive while increasing detail as zoom grows,
  /// reducing under-iteration artifacts in deep zoom.
  ///
  /// Scaling curve:
  /// - zoom <= 1: unchanged
  /// - zoom > 1: base * (1 + 0.35 * log10(zoom))
  /// - clamped to [4, gpuMaxIterations]
  int scaledGpuIterations({
    required int baseIterations,
    required double zoom,
  }) {
    final safeBase = baseIterations.clamp(4, gpuMaxIterations);
    final depth = _zoomDepthLog10(zoom);
    if (depth == 0.0) return safeBase;

    final factor = 1.0 + 0.35 * depth;
    final scaled = (safeBase * factor).round();
    return scaled.clamp(4, gpuMaxIterations);
  }
}

double _zoomDepthLog10(double zoom) {
  if (zoom.isNaN || zoom <= 1.0) return 0.0;
  if (zoom.isInfinite) return 30.0;
  return (math.log(zoom) / math.ln10).clamp(0.0, 30.0);
}

/// Replayable state for one GPU→CPU deep-zoom hysteresis streak.
///
/// Keeping the transition pure makes the hidden state/order dependence visible:
/// streaks are scoped to one module, below-threshold samples reset immediately,
/// and CPU fallback activates only after enough consecutive above-threshold
/// samples for the same module.
@immutable
class DeepZoomHysteresisState {
  final String? moduleId;
  final int aboveThresholdCount;
  final bool cpuActive;

  const DeepZoomHysteresisState({
    required this.moduleId,
    required this.aboveThresholdCount,
    required this.cpuActive,
  });

  const DeepZoomHysteresisState.initial()
      : moduleId = null,
        aboveThresholdCount = 0,
        cpuActive = false;

  DeepZoomHysteresisState next({
    required String nextModuleId,
    required bool overThreshold,
    required int activationFrames,
  }) {
    assert(activationFrames > 0, 'activationFrames must be positive');
    final sameModule = moduleId == nextModuleId;
    final currentCount = sameModule ? aboveThresholdCount : 0;

    if (!overThreshold) {
      return DeepZoomHysteresisState(
        moduleId: nextModuleId,
        aboveThresholdCount: 0,
        cpuActive: false,
      );
    }

    final nextCount = currentCount + 1;
    return DeepZoomHysteresisState(
      moduleId: nextModuleId,
      aboveThresholdCount: nextCount,
      cpuActive: nextCount >= activationFrames,
    );
  }
}

/// Stateful hysteresis filter for GPU→CPU deep-zoom transitions.
///
/// Wraps [DeepZoomPrecisionPolicy] and requires [policy.hysteresisFrames]
/// consecutive above-threshold evaluations before reporting CPU needed.
/// Drops back to GPU immediately when zoom falls below threshold.
class DeepZoomHysteresis {
  final DeepZoomPrecisionPolicy policy;
  DeepZoomHysteresisState _state = const DeepZoomHysteresisState.initial();

  DeepZoomHysteresis({this.policy = const DeepZoomPrecisionPolicy()});

  DeepZoomHysteresisState get state => _state;

  /// Call this on every zoom change. Returns true if CPU fallback is warranted.
  bool update({required String moduleId, required double zoom}) {
    final overThreshold = policy.shouldUseCpuFallback(
      moduleId: moduleId,
      zoom: zoom,
    );

    _state = _state.next(
      nextModuleId: moduleId,
      overThreshold: overThreshold,
      activationFrames: policy.hysteresisFrames,
    );
    return _state.cpuActive;
  }

  void reset() {
    _state = const DeepZoomHysteresisState.initial();
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/features/renderer/deep_zoom_precision_policy.dart';

void main() {
  const policy = DeepZoomPrecisionPolicy();

  group('DeepZoomPrecisionPolicy.thresholdsFor', () {
    test('exposes contiguous Mandelbrot df2 to CPU fallback boundaries', () {
      final thresholds = policy.thresholdsFor('mandelbrot');

      expect(thresholds.supportsDoubleFloat, isTrue);
      expect(thresholds.doubleFloatLowerZoom, 5e6);
      expect(thresholds.doubleFloatUpperZoom, thresholds.cpuFallbackZoom);
      expect(thresholds.shouldUseDoubleFloat(1e11), isTrue);
      expect(
        thresholds.shouldUseDoubleFloat(thresholds.cpuFallbackZoom),
        isFalse,
      );
      expect(
        thresholds.shouldUseCpuFallback(thresholds.cpuFallbackZoom),
        isTrue,
      );
    });

    test('exposes default thresholds without a double-float range', () {
      final thresholds = policy.thresholdsFor('unknown_fractal');

      expect(thresholds.cpuFallbackZoom, 1e7);
      expect(thresholds.supportsDoubleFloat, isFalse);
      expect(thresholds.shouldUseDoubleFloat(1e10), isFalse);
    });
  });

  group('DeepZoomPrecisionPolicy.decisionFor', () {
    test('exposes CPU and double-float routing from one threshold snapshot',
        () {
      final decision = policy.decisionFor(moduleId: 'mandelbrot', zoom: 1e10);

      expect(decision.moduleId, 'mandelbrot');
      expect(decision.zoom, 1e10);
      expect(decision.cpuFallbackZoom, 1e12);
      expect(decision.shouldUseDoubleFloat, isTrue);
      expect(decision.shouldUseCpuFallback, isFalse);
      expect(decision.thresholds, same(policy.thresholdsFor('mandelbrot')));
    });

    test('keeps invalid zoom samples below precision routing thresholds', () {
      for (final zoom in [double.nan, double.negativeInfinity]) {
        final decision = policy.decisionFor(
          moduleId: 'mandelbrot',
          zoom: zoom,
        );

        expect(decision.shouldUseDoubleFloat, isFalse, reason: '$zoom');
        expect(decision.shouldUseCpuFallback, isFalse, reason: '$zoom');
      }
    });
  });

  group('DeepZoomPrecisionPolicy.shouldUseCpuFallback', () {
    test('returns false for mandelbrot at zoom 1e6', () {
      expect(
        policy.shouldUseCpuFallback(moduleId: 'mandelbrot', zoom: 1e6),
        isFalse,
      );
    });

    test('returns true for mandelbrot at zoom 1e15', () {
      expect(
        policy.shouldUseCpuFallback(moduleId: 'mandelbrot', zoom: 1e15),
        isTrue,
      );
    });

    test('uses default threshold for unknown module', () {
      // Default threshold is 1e7; zoom just below should be false.
      expect(
        policy.shouldUseCpuFallback(moduleId: 'unknown_fractal', zoom: 9.9e6),
        isFalse,
      );
      // At or above default threshold (1e7) should be true.
      expect(
        policy.shouldUseCpuFallback(moduleId: 'unknown_fractal', zoom: 1e7),
        isTrue,
      );
    });
  });

  group('DeepZoomPrecisionPolicy.shouldUseDoubleFloat', () {
    test('returns true for mandelbrot in df2 range', () {
      // df2 range: [5e6, 1e12)
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 5e6),
        isTrue,
      );
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 1e10),
        isTrue,
      );
    });

    test('returns false for non-mandelbrot modules', () {
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'julia', zoom: 1e10),
        isFalse,
      );
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'burning_ship', zoom: 1e10),
        isFalse,
      );
    });

    test('returns false below df2 lower threshold', () {
      // Below 5e6 the standard float32 shader is sufficient.
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 1e5),
        isFalse,
      );
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 4.9e6),
        isFalse,
      );
    });

    test('returns false at or above df2 upper threshold', () {
      // At 1e12 CPU fallback takes over; df2 should not be active.
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 1e12),
        isFalse,
      );
    });
  });

  group('DeepZoomPrecisionPolicy.scaledGpuIterations', () {
    test('returns base at zoom 1', () {
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: 1.0),
        equals(256),
      );
    });

    test('returns base at zoom below 1', () {
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: 0.5),
        equals(256),
      );
    });

    test('increases with zoom depth', () {
      final atZoom1 =
          policy.scaledGpuIterations(baseIterations: 256, zoom: 1.0);
      final atZoom1e6 =
          policy.scaledGpuIterations(baseIterations: 256, zoom: 1e6);
      expect(atZoom1e6, greaterThan(atZoom1));
    });

    test('clamps to gpuMaxIterations', () {
      // Very high base + very high zoom should be clamped.
      final result = policy.scaledGpuIterations(
        baseIterations: DeepZoomPrecisionPolicy.gpuMaxIterations,
        zoom: 1e30,
      );
      expect(result, equals(DeepZoomPrecisionPolicy.gpuMaxIterations));
    });

    test('clamps low base to minimum of 4', () {
      final result = policy.scaledGpuIterations(baseIterations: 1, zoom: 1.0);
      expect(result, equals(4));
    });

    test('treats non-finite zoom values as bounded inputs', () {
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: double.nan),
        equals(256),
      );
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: double.infinity),
        equals(DeepZoomPrecisionPolicy.gpuMaxIterations),
      );
      expect(
        policy.scaledGpuIterations(
          baseIterations: 256,
          zoom: double.negativeInfinity,
        ),
        equals(256),
      );
    });
  });

  group('DeepZoomHysteresisState', () {
    test('exposes replayable streak transitions', () {
      const initial = DeepZoomHysteresisState.initial();

      final first = initial.next(
        nextModuleId: 'julia',
        overThreshold: true,
        activationFrames: 2,
      );
      final second = first.next(
        nextModuleId: 'julia',
        overThreshold: true,
        activationFrames: 2,
      );
      final resetByZoomOut = second.next(
        nextModuleId: 'julia',
        overThreshold: false,
        activationFrames: 2,
      );
      final resetByModule = first.next(
        nextModuleId: 'mandelbrot',
        overThreshold: true,
        activationFrames: 2,
      );

      expect(first.moduleId, 'julia');
      expect(first.aboveThresholdCount, 1);
      expect(first.cpuActive, isFalse);
      expect(second.aboveThresholdCount, 2);
      expect(second.cpuActive, isTrue);
      expect(resetByZoomOut.aboveThresholdCount, 0);
      expect(resetByZoomOut.cpuActive, isFalse);
      expect(resetByModule.moduleId, 'mandelbrot');
      expect(resetByModule.aboveThresholdCount, 1);
      expect(resetByModule.cpuActive, isFalse);
    });
  });

  group('DeepZoomHysteresis', () {
    test('does not activate CPU until hysteresisFrames consecutive frames', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);
      // mandelbrot CPU threshold is 1e12; zoom 2e12 is above it.
      const moduleId = 'mandelbrot';
      const highZoom = 2e12;
      final frames = policy.hysteresisFrames;

      // All frames before the last should still return false.
      for (var i = 0; i < frames - 1; i++) {
        expect(
          hysteresis.update(moduleId: moduleId, zoom: highZoom),
          isFalse,
          reason: 'frame $i should not activate CPU yet',
        );
      }

      // The hysteresisFrames-th frame should activate.
      expect(
        hysteresis.update(moduleId: moduleId, zoom: highZoom),
        isTrue,
      );
    });

    test('drops back to GPU immediately when zoom falls below threshold', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);
      const moduleId = 'mandelbrot';
      const highZoom = 2e14;
      const lowZoom = 1.0;
      final frames = policy.hysteresisFrames;

      // Trigger CPU mode.
      for (var i = 0; i < frames; i++) {
        hysteresis.update(moduleId: moduleId, zoom: highZoom);
      }

      // A single below-threshold update drops back to GPU.
      expect(
        hysteresis.update(moduleId: moduleId, zoom: lowZoom),
        isFalse,
      );
    });

    test('does not carry above-threshold count across module changes', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);

      expect(
        hysteresis.update(moduleId: 'julia', zoom: 2e9),
        isFalse,
        reason: 'first Julia deep-zoom frame should only prime hysteresis',
      );

      expect(
        hysteresis.update(moduleId: 'mandelbrot', zoom: 2e14),
        isFalse,
        reason: 'first Mandelbrot deep-zoom frame must not inherit Julia count',
      );

      expect(
        hysteresis.update(moduleId: 'mandelbrot', zoom: 2e14),
        isTrue,
        reason: 'second consecutive Mandelbrot deep-zoom frame activates CPU',
      );
    });

    test('reset clears state so hysteresis counter restarts', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);
      const moduleId = 'mandelbrot';
      const highZoom = 2e14;
      final frames = policy.hysteresisFrames;

      // Build up to just before activation.
      for (var i = 0; i < frames - 1; i++) {
        hysteresis.update(moduleId: moduleId, zoom: highZoom);
      }

      hysteresis.reset();

      // After reset, the counter is zero; a single update should not activate.
      expect(
        hysteresis.update(moduleId: moduleId, zoom: highZoom),
        isFalse,
      );
    });
  });
}

