import 'dart:collection';
import 'dart:convert';
import 'dart:io';

import 'package:flutter/foundation.dart';
import 'package:path_provider/path_provider.dart';

/// Severity levels for log entries.
enum LogLevel { debug, info, warn, error }

/// A single timestamped log entry.
class LogEntry {
  LogEntry({
    required this.timestamp,
    required this.level,
    required this.category,
    required this.message,
    this.data,
  });

  final DateTime timestamp;
  final LogLevel level;

  /// Short tag: 'action', 'render', 'gpu', 'state', 'lifecycle', 'export', etc.
  final String category;
  final String message;

  /// Optional structured data (e.g. fractal state snapshot).
  final Map<String, Object?>? data;

  Map<String, Object?> toJson() => {
        't': timestamp.toIso8601String(),
        'level': level.name,
        'cat': category,
        'msg': message,
        if (data != null) 'data': data,
      };

  /// Serialises to a JSONL line using the on-disk schema.
  Map<String, Object?> toDiskJson() => {
        'timestamp': timestamp.toIso8601String(),
        'level': level.name,
        'tag': category,
        'message': message,
      };

  /// Deserialises from the on-disk JSONL schema.
  factory LogEntry.fromDiskJson(Map<String, dynamic> json) {
    return LogEntry(
      timestamp: DateTime.parse(json['timestamp'] as String),
      level: LogLevel.values.firstWhere(
        (l) => l.name == (json['level'] as String),
        orElse: () => LogLevel.info,
      ),
      category: json['tag'] as String? ?? '',
      message: json['message'] as String? ?? '',
    );
  }

  String toLogLine() {
    final ts =
        '${timestamp.hour.toString().padLeft(2, '0')}:${timestamp.minute.toString().padLeft(2, '0')}:${timestamp.second.toString().padLeft(2, '0')}.${timestamp.millisecond.toString().padLeft(3, '0')}';
    final dataStr = data != null ? ' ${jsonEncode(data)}' : '';
    return '[$ts][${level.name}][$category] $message$dataStr';
  }
}

/// Global in-memory ring-buffer logger with optional persistent JSONL storage.
///
/// Keeps the last [maxEntries] log entries in memory. Export as text or JSON
/// at any time via [exportText] / [exportJson].
///
/// Call [init] once at app startup to enable persistence:
/// ```dart
/// await AppLogger.instance.init();
/// ```
///
/// Usage:
/// ```dart
/// AppLogger.instance.log('action', 'User tapped zoom reset');
/// AppLogger.instance.logState('render', 'Backend switched', {'backend': 'cpu', 'reason': 'gpu_health'});
/// ```
class AppLogger extends ChangeNotifier {
  AppLogger._({this.maxEntries = 2000}); // ignore: unused_element_parameter

  static final AppLogger instance = AppLogger._();

  /// Maximum entries kept in the ring buffer.
  final int maxEntries;

  /// Maximum entries persisted to disk (rotation threshold).
  static const int _maxDiskEntries = 5000;

  /// Approximate size cap for the on-disk file (~2 MB).
  static const int _maxDiskBytes = 2 * 1024 * 1024;

  final Queue<LogEntry> _entries = Queue<LogEntry>();

  File? _logFile;
  IOSink? _sink;
  bool _persistenceReady = false;

  /// Read-only view of all entries (oldest first).
  List<LogEntry> get entries => _entries.toList(growable: false);

  int get length => _entries.length;

  // ── Initialisation ──────────────────────────────────────────────────

  /// Initialise persistent storage. Safe to call multiple times; subsequent
  /// calls are no-ops. Skipped automatically on web (no filesystem).
  Future<void> init() async {
    if (_persistenceReady) return;
    if (kIsWeb) return;

    try {
      final cacheDir = await getApplicationCacheDirectory();
      _logFile = File('${cacheDir.path}/fractal_forge_logs.jsonl');
      await _loadFromDisk();
      _sink = _logFile!.openWrite(mode: FileMode.append);
      _persistenceReady = true;
    } catch (e) {
      if (kDebugMode) {
        debugPrint('[AppLogger] Failed to init persistence: $e');
      }
      // Graceful degradation: continue with in-memory only.
      _logFile = null;
      _sink = null;
    }
  }

  // ── Disk I/O ────────────────────────────────────────────────────────

  Future<void> _loadFromDisk() async {
    final file = _logFile;
    if (file == null || !file.existsSync()) return;

    try {
      final lines = await file.readAsLines();

      // Rotation: keep only the last _maxDiskEntries lines that fit within
      // _maxDiskBytes when re-encoded.
      final validLines = <String>[];
      int totalBytes = 0;
      for (final line in lines.reversed) {
        if (line.trim().isEmpty) continue;
        totalBytes += line.length + 1; // +1 for newline
        if (validLines.length >= _maxDiskEntries || totalBytes > _maxDiskBytes) {
          break;
        }
        validLines.add(line);
      }
      // Restore chronological order.
      final keptLines = validLines.reversed.toList();

      // If we trimmed anything, rewrite the file to reclaim space.
      if (keptLines.length < lines.where((l) => l.trim().isNotEmpty).length) {
        await file.writeAsString(keptLines.map((l) => '$l\n').join());
      }

      // Parse and load into ring buffer (in-memory max still applies).
      for (final line in keptLines) {
        try {
          final json = jsonDecode(line) as Map<String, dynamic>;
          final entry = LogEntry.fromDiskJson(json);
          _entries.addLast(entry);
          while (_entries.length > maxEntries) {
            _entries.removeFirst();
          }
        } catch (_) {
          // Skip malformed lines.
        }
      }
    } catch (e) {
      if (kDebugMode) {
        debugPrint('[AppLogger] Failed to load log from disk: $e');
      }
    }
  }

  void _appendToDisk(LogEntry entry) {
    final sink = _sink;
    if (sink == null) return;

    try {
      sink.writeln(jsonEncode(entry.toDiskJson()));
    } catch (e) {
      if (kDebugMode) {
        debugPrint('[AppLogger] Failed to write log entry to disk: $e');
      }
    }
  }

  // ── Logging methods ────────────────────────────────────────────────

  void log(String category, String message,
      {LogLevel level = LogLevel.info, Map<String, Object?>? data}) {
    final entry = LogEntry(
      timestamp: DateTime.now(),
      level: level,
      category: category,
      message: message,
      data: data,
    );
    _entries.addLast(entry);
    while (_entries.length > maxEntries) {
      _entries.removeFirst();
    }
    if (kDebugMode) {
      debugPrint(entry.toLogLine());
    }
    _appendToDisk(entry);
    notifyListeners();
  }

  /// Convenience: log with structured data.
  void logState(String category, String message, Map<String, Object?> data,
      {LogLevel level = LogLevel.info}) {
    log(category, message, level: level, data: data);
  }

  void debug(String category, String message, {Map<String, Object?>? data}) =>
      log(category, message, level: LogLevel.debug, data: data);

  void info(String category, String message, {Map<String, Object?>? data}) =>
      log(category, message, level: LogLevel.info, data: data);

  void warn(String category, String message, {Map<String, Object?>? data}) =>
      log(category, message, level: LogLevel.warn, data: data);

  void error(String category, String message, {Map<String, Object?>? data}) =>
      log(category, message, level: LogLevel.error, data: data);

  // ── Export ──────────────────────────────────────────────────────────

  /// Plain-text export (one line per entry).
  String exportText({LogLevel? minLevel}) {
    final filtered = minLevel == null
        ? _entries
        : _entries.where((e) => e.level.index >= minLevel.index);
    return filtered.map((e) => e.toLogLine()).join('\n');
  }

  /// JSON array export.
  String exportJson({LogLevel? minLevel, bool pretty = true}) {
    final filtered = minLevel == null
        ? _entries
        : _entries.where((e) => e.level.index >= minLevel.index);
    final list = filtered.map((e) => e.toJson()).toList();
    return pretty
        ? const JsonEncoder.withIndent('  ').convert(list)
        : jsonEncode(list);
  }

  // ── Clear ────────────────────────────────────────────────────────────

  /// Clear all entries from memory and truncate the on-disk file.
  Future<void> clearLog() async {
    _entries.clear();
    await _truncateDisk();
    notifyListeners();
  }

  /// Synchronous clear (in-memory only; schedules disk truncation).
  void clear() {
    _entries.clear();
    _truncateDisk(); // fire-and-forget
    notifyListeners();
  }

  Future<void> _truncateDisk() async {
    final file = _logFile;
    if (file == null || !_persistenceReady) return;

    try {
      // Close the current sink, truncate the file, reopen for append.
      await _sink?.flush();
      await _sink?.close();
      _sink = null;
      await file.writeAsString('');
      _sink = file.openWrite(mode: FileMode.append);
    } catch (e) {
      if (kDebugMode) {
        debugPrint('[AppLogger] Failed to truncate log file: $e');
      }
    }
  }

  // ── Dispose ──────────────────────────────────────────────────────────

  @override
  Future<void> dispose() async {
    try {
      await _sink?.flush();
      await _sink?.close();
    } catch (_) {}
    _sink = null;
    super.dispose();
  }
}

import 'dart:convert';
import 'dart:io';

import 'package:flutter_fractals/core/services/app_logger_service.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  // Use a fresh AppLogger per test so ring-buffer state does not bleed.
  late AppLogger logger;

  setUp(() async {
    // Clear the singleton's ring buffer before each test.
    await AppLogger.instance.clearLog();
    logger = AppLogger.instance;
  });

  group('AppLogger — ring buffer', () {
    test('log adds entry to ring buffer', () {
      expect(logger.length, 0);
      logger.log('render', 'frame rendered');
      expect(logger.length, 1);
      expect(logger.entries.first.message, 'frame rendered');
      expect(logger.entries.first.category, 'render');
    });

    test('log trims to maxEntries when exceeded', () {
      // maxEntries defaults to 2000; use reflection-free approach: add
      // maxEntries+1 items and verify oldest is removed.
      final max = logger.maxEntries;
      for (int i = 0; i <= max; i++) {
        logger.log('cat', 'msg$i');
      }
      expect(logger.length, max);
      // First entry should be msg1 (msg0 was trimmed)
      expect(logger.entries.first.message, 'msg1');
      expect(logger.entries.last.message, 'msg$max');
    });

    test('entries returns oldest-first list', () {
      logger.log('a', 'first');
      logger.log('b', 'second');
      logger.log('c', 'third');

      final entries = logger.entries;
      expect(entries[0].message, 'first');
      expect(entries[1].message, 'second');
      expect(entries[2].message, 'third');
    });
  });

  group('AppLogger — convenience level methods', () {
    test('debug sets level to debug', () {
      logger.debug('cat', 'dbg msg');
      expect(logger.entries.last.level, LogLevel.debug);
    });

    test('info sets level to info', () {
      logger.info('cat', 'info msg');
      expect(logger.entries.last.level, LogLevel.info);
    });

    test('warn sets level to warn', () {
      logger.warn('cat', 'warn msg');
      expect(logger.entries.last.level, LogLevel.warn);
    });

    test('error sets level to error', () {
      logger.error('cat', 'error msg');
      expect(logger.entries.last.level, LogLevel.error);
    });

    test('log default level is info', () {
      logger.log('cat', 'default level');
      expect(logger.entries.last.level, LogLevel.info);
    });
  });

  group('AppLogger — exportText', () {
    test('exportText returns all entries as lines', () {
      logger.log('a', 'line one');
      logger.log('b', 'line two');
      logger.log('c', 'line three');

      final text = logger.exportText();
      final lines = text.split('\n');
      expect(lines.length, 3);
      expect(lines[0], contains('line one'));
      expect(lines[1], contains('line two'));
      expect(lines[2], contains('line three'));
    });

    test('exportText with minLevel filters lower levels', () {
      logger.debug('cat', 'debug entry');
      logger.info('cat', 'info entry');
      logger.warn('cat', 'warn entry');
      logger.error('cat', 'error entry');

      final text = logger.exportText(minLevel: LogLevel.warn);
      expect(text, contains('warn entry'));
      expect(text, contains('error entry'));
      expect(text, isNot(contains('debug entry')));
      expect(text, isNot(contains('info entry')));
    });
  });

  group('AppLogger — exportJson', () {
    test('exportJson returns valid JSON array', () {
      logger.log('render', 'gpu frame');
      logger.log('action', 'user tapped');

      final json = logger.exportJson();
      final decoded = jsonDecode(json);
      expect(decoded, isA<List>());
      expect((decoded as List).length, 2);
    });

    test('exportJson entries contain expected keys', () {
      logger.log('render', 'test', data: {'frames': 42});

      final decoded = jsonDecode(logger.exportJson()) as List;
      final entry = decoded.first as Map<String, dynamic>;
      expect(entry['level'], isNotNull);
      expect(entry['cat'], isNotNull);
      expect(entry['msg'], isNotNull);
      expect(entry['t'], isNotNull);
      expect(entry['data'], {'frames': 42});
    });

    test('exportJson with minLevel filters entries', () {
      logger.debug('cat', 'skip me');
      logger.error('cat', 'keep me');

      final decoded = jsonDecode(logger.exportJson(minLevel: LogLevel.error))
          as List;
      expect(decoded.length, 1);
      expect((decoded.first as Map)['msg'], 'keep me');
    });

    test('exportJson pretty=false returns compact JSON', () {
      logger.log('cat', 'compact');
      final json = logger.exportJson(pretty: false);
      // Compact JSON has no newlines
      expect(json, isNot(contains('\n')));
    });
  });

  group('AppLogger — clear', () {
    test('clear removes all entries', () async {
      logger.log('a', 'one');
      logger.log('b', 'two');
      expect(logger.length, 2);

      await logger.clearLog();
      expect(logger.length, 0);
      expect(logger.entries, isEmpty);
    });

    test('clearLog notifies listeners', () async {
      logger.log('a', 'entry');
      int notifyCount = 0;
      logger.addListener(() => notifyCount++);

      await logger.clearLog();
      expect(notifyCount, 1);
    });

    test('clear (sync) notifies listeners', () {
      logger.log('a', 'entry');
      int notifyCount = 0;
      logger.addListener(() => notifyCount++);

      logger.clear();
      expect(notifyCount, 1);
    });

    test('log notifies listeners', () {
      int notifyCount = 0;
      logger.addListener(() => notifyCount++);

      logger.log('cat', 'msg');
      expect(notifyCount, 1);
    });
  });

  group('LogEntry.toLogLine', () {
    test('formats correctly with HH:MM:SS.mmm prefix', () {
      final entry = LogEntry(
        timestamp: DateTime(2024, 1, 15, 9, 5, 3, 42),
        level: LogLevel.info,
        category: 'render',
        message: 'hello world',
      );

      final line = entry.toLogLine();
      expect(line, startsWith('[09:05:03.042]'));
      expect(line, contains('[info]'));
      expect(line, contains('[render]'));
      expect(line, contains('hello world'));
    });

    test('toLogLine includes JSON-encoded data when present', () {
      final entry = LogEntry(
        timestamp: DateTime(2024, 6, 1, 12, 0, 0, 0),
        level: LogLevel.warn,
        category: 'gpu',
        message: 'health check',
        data: {'status': 'failed', 'code': 3},
      );

      final line = entry.toLogLine();
      expect(line, contains('"status":"failed"'));
      expect(line, contains('"code":3'));
    });

    test('toLogLine has no data suffix when data is null', () {
      final entry = LogEntry(
        timestamp: DateTime(2024, 6, 1, 12, 0, 0, 0),
        level: LogLevel.debug,
        category: 'action',
        message: 'tap',

[131 more lines in file. Use offset=221 to continue.]

      );

      final line = entry.toLogLine();
      // Should end with the message, no trailing data
      expect(line, endsWith('tap'));
    });

    test('toLogLine level ordering: debug < info < warn < error', () {
      expect(LogLevel.debug.index, lessThan(LogLevel.info.index));
      expect(LogLevel.info.index, lessThan(LogLevel.warn.index));
      expect(LogLevel.warn.index, lessThan(LogLevel.error.index));
    });
  });

  group('LogEntry — disk serialisation', () {
    test('toDiskJson uses required keys', () {
      final entry = LogEntry(
        timestamp: DateTime(2024, 3, 10, 8, 0, 0),
        level: LogLevel.warn,
        category: 'render',
        message: 'slow frame',
      );
      final json = entry.toDiskJson();
      expect(json['timestamp'], isA<String>());
      expect(json['level'], 'warn');
      expect(json['tag'], 'render');
      expect(json['message'], 'slow frame');
    });

    test('fromDiskJson round-trips correctly', () {
      final original = LogEntry(
        timestamp: DateTime(2025, 6, 15, 10, 30, 45, 123),
        level: LogLevel.error,
        category: 'gpu',
        message: 'out of memory',
      );
      final json = original.toDiskJson();
      final restored = LogEntry.fromDiskJson(json);

      expect(restored.timestamp.toIso8601String(),
          original.timestamp.toIso8601String());
      expect(restored.level, original.level);
      expect(restored.category, original.category);
      expect(restored.message, original.message);
    });

    test('fromDiskJson with unknown level falls back to info', () {
      final json = {
        'timestamp': DateTime.now().toIso8601String(),
        'level': 'unknown_level',
        'tag': 'test',
        'message': 'msg',
      };
      final entry = LogEntry.fromDiskJson(json);
      expect(entry.level, LogLevel.info);
    });
  });

  group('AppLogger — file persistence (temp directory)', () {
    late Directory tempDir;
    late File logFile;

    setUp(() async {
      tempDir = await Directory.systemTemp.createTemp('app_logger_test_');
      logFile = File('${tempDir.path}/fractal_forge_logs.jsonl');
    });

    tearDown(() async {
      await tempDir.delete(recursive: true);
    });

    test('_loadFromDisk populates ring buffer from existing JSONL', () async {
      // Write two pre-existing JSONL entries.
      final lines = [
        jsonEncode({
          'timestamp': '2024-01-01T10:00:00.000',
          'level': 'info',
          'tag': 'render',
          'message': 'loaded from disk',
        }),
        jsonEncode({
          'timestamp': '2024-01-01T10:00:01.000',
          'level': 'warn',
          'tag': 'gpu',
          'message': 'second entry',
        }),
      ];
      await logFile.writeAsString(lines.map((l) => '$l\n').join());

      // Parse directly via fromDiskJson to verify the round-trip.
      final readBack = await logFile.readAsLines();
      final parsed = readBack
          .where((l) => l.trim().isNotEmpty)
          .map((l) => LogEntry.fromDiskJson(jsonDecode(l) as Map<String, dynamic>))
          .toList();

      expect(parsed.length, 2);
      expect(parsed[0].message, 'loaded from disk');
      expect(parsed[0].category, 'render');
      expect(parsed[0].level, LogLevel.info);
      expect(parsed[1].message, 'second entry');
      expect(parsed[1].level, LogLevel.warn);
    });

    test('toDiskJson produces valid JSONL-parseable output', () {
      final entry = LogEntry(
        timestamp: DateTime(2025, 1, 1, 0, 0, 0),
        level: LogLevel.debug,
        category: 'action',
        message: 'test message',
      );
      final line = jsonEncode(entry.toDiskJson());
      // Must be valid JSON and single-line.
      expect(() => jsonDecode(line), returnsNormally);
      expect(line, isNot(contains('\n')));
    });

    test('malformed JSONL lines are skipped gracefully', () {
      const bad = '{"timestamp": "not-a-date", bad json}';
      expect(
        () => LogEntry.fromDiskJson(
            jsonDecode('{"timestamp":"2024-01-01T00:00:00.000","level":"info","tag":"x","message":"y"}')
                as Map<String, dynamic>),
        returnsNormally,
      );
      // Malformed JSON should throw during jsonDecode — catch is in _loadFromDisk.
      expect(() => jsonDecode(bad), throwsA(isA<FormatException>()));
    });
  });
}

